form:Form.form:Scripts:
		function c_cargo_siafca_onchange(pCtrl) {

	var value = pCtrl.GetXValue();

	if (value != "") {

		var regexp = /^[A-Za-z0-9]-[A-Za-z0-9]{2}-[A-Za-z0-9]{4}$/;

		if(!regexp.test(value)) { 
			alert("El valor '" + value + "' ingresado en el campo 'Cargo SIAFCA' no era el correcto y fue eliminado. Por favor, vuelva a ingresarlo con el siguiente formato: X-XX-XXXX.");
			pCtrl.SetXValue("");
			pCtrl.SetFocus();
			return false;
		}
	}

	return true;  
}
